var e=JSON.parse(`[{"id":"L5_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_PAST","text":{"KOREA":"너희는 서둘러 도시를 탈출해라.","JPN":"君たちは急いで都市から脱出しろ。","ENG":"You should hurry and escape the city.","TWN":"你們兩個迅速撤出城市。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_PAST","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_PAST","text":{"KOREA":"나는 이곳에서 끝을 보겠다.","JPN":"私はここで決着をつける。","ENG":"I will see how this ends here.","TWN":"我會在這裡結束一切。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_PAST","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_PAST","text":{"KOREA":"만트라 코드를 잊어버린 지금, 놈을 상대할 수 있는 건 나뿐이다.","JPN":"マントラコードを忘れた今、やつの相手をできるのは私だけだ。","ENG":"With the mantra code forgotten, the only one who can deal with it is me.","TWN":"既然已經記不得曼陀羅代碼，那能對付那傢伙的就只有我。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_PAST","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_NULL","text":{"KOREA":"음? 그건 좀 힘들겠는데?","JPN":"ん？　それは難しいぞ。","ENG":"Hmm? That's not going to happen.","TWN":"嗯？恐怕有點困難。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_NULL","text":{"KOREA":"내가 허락 안 해줄 거거든.\xA0","JPN":"俺が許可しないからな。\xA0","ENG":"Because I won't allow it.\xA0","TWN":"因為我可不同意。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_PAST","text":{"KOREA":"윽……! 공간이 제멋대로……! ","JPN":"うっ……！　勝手に空間が……！ ","ENG":"Ngh...! The space is doing it again...!","TWN":"呃……！空間在變化……！"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_PAST","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_PAST","text":{"KOREA":"움직일 수 없어……?","JPN":"動けない……？","ENG":"I can't move...?","TWN":"沒辦法動……？"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_PAST","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_PAST","text":{"KOREA":"라비! 이게 무슨 짓이지?","JPN":"ラビ！　何のつもりだ？","ENG":"Ravi! What's the meaning of this?","TWN":"你在做什麼？拉維！"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_PAST","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_NULL","text":{"KOREA":"내 CRF를 억지로 뽑아내서 차원 닻으로 내보낼 수 있는 인원은 한 명이 한계야.","JPN":"俺のCRFを無理やり引き抜いても、次元錨で送れる人数は精々一人までだ。","ENG":"Squeezing every ounce of CRF in me, I can only send one person by the Dimension Anchor.","TWN":"就算用光我所有的CRF，也只能用次元錨送出去一個人。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_NULL","text":{"KOREA":"지휘관은 귀중한 자원이니, 우리가 나서서 시간을 끌어야 하지 않겠나?","JPN":"指揮官は貴重な資源だから、俺たちが時間を稼ぐべきだろう。","ENG":"Commanders are a valuable asset, so don't you think we should step in and buy you some time?","TWN":"戰隊長是寶貴的資源，應該由我們來拖延時間，不是嗎？"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_PAST","text":{"KOREA":"말도 안 되는 소리 마라! 지휘관은 끝까지 남아 전선을 지켜야 해!","JPN":"ふざけるな！　指揮官は最後まで戦線を守らないといけない！","ENG":"Don't be ridiculous! A commander must stay at the frontlines and defend it!","TWN":"別說這種話！戰隊長必須堅守到最後，守住前線！"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_PAST","text":{"KOREA":"그리고 저 침식체가 뭔지 잘 알고 있잖아!","JPN":"それに、あの侵食体がいったい何なのかよくわかっているだろう！","ENG":"And you know just as well as I do what that C.O. is!","TWN":"而且你很清楚那是什麼侵蝕體！"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_PAST","text":{"KOREA":"내 부하들이야! 그리고 우리의 함선이라고! 배를 버리고 도망가는 선장은 없다!","JPN":"私の部下だ！　そして私たちの艦船なんだ！　船を捨てて逃げる船長などいない！","ENG":"They are my subordinates! And it's our ship! No captain abandons ship and runs away!","TWN":"他們是我的部下！而那是我們的艦船！船長是不會棄船而逃的！"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_PAST","text":{"KOREA":"적어도 나는 저 녀석들과 함께해야 해! 부하를 버리고 혼자 살아남는 비겁자가 되라는 건가?!","JPN":"少なくとも私はあいつらと一緒にいなければならない！　部下を見捨てて一人生き残る卑怯者になれというのか！？","ENG":"I must at least be with them! Or do you want me to become a coward who left my subordinates and survived alone?!","TWN":"至少我得和他們在一起！你是要我拋棄部下，自己一個人苟且偷生嗎？！"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_NULL","text":{"KOREA":"아샤에게 안부나 전해줘. 아마 때가 되면 널 찾아올 거야.","JPN":"アーシャによろしく伝えてくれ。恐らく、時が来ればお前を訪ねてくるだろうさ。","ENG":"Say hello to Asha for me. She'll come find you when the time is right.","TWN":"替我向阿莎問好。或許時機成熟時，她會來找你。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_NULL","text":{"KOREA":"많이 힘들어할 테니까…… 나 대신 아샤를 지켜줘.","JPN":"とてもつらいと思うから……俺の代わりにアーシャを守ってくれ。","ENG":"She'll have been through a lot, so... protect Asha for me.","TWN":"那孩子一個人會很辛苦……請替我保護好她。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_PAST","text":{"KOREA":"아샤는…… 네가 지키면 되는 거잖아…… 아닐라, 너도…… 어서……!","JPN":"アーシャは……君が守ればいいだろう……アニラ、君も……早く……！","ENG":"You can... protect Asha yourself... Anila, you too... Hurry...!","TWN":"阿莎……你自己保護吧……雅妮拉，你也一樣……！"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_PAST","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_PAST","text":{"KOREA":"당장 공간 제어를 멈춰라! 이건…… 명령 불복종이다!","JPN":"今すぐ空間制御を止めろ！　これは……命令不服従だぞ！","ENG":"Stop controlling the space this instant! You are... disobeying direct orders!","TWN":"馬上解開空間控制！你這是……違抗命令！"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_PAST","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NULL","text":{"KOREA":"아하하. 저희는 침식체 내부에서 작전을 수행하겠습니다.","JPN":"あはは。私たちは侵食体の内部で作戦を遂行します。","ENG":"Ah hah hah. We'll continue the operation from within the C.O.","TWN":"呵呵呵，我們會繼續在侵蝕體體內執行任務的。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NULL","text":{"KOREA":"아디트야 님이 우릴 내보내고 싸우려는 이유도 힘을 제어할 방법을 잊었기 때문이잖아요.","JPN":"アーディティヤ様が私たちを外に出して戦おうとしている理由も、力を制御する方法を忘れているからでしょう？","ENG":"Miss Aditya, you're trying to push us out and fight alone because you've forgotten how to control your powers.","TWN":"你之所以要把我們送走自己留下來作戰，也是因為忘記控制力量的方法吧？"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NULL","text":{"KOREA":"저도 많은 기억을 잃었어요.","JPN":"私もたくさんの記憶を失いました。","ENG":"I've also lost a lot of memories.","TWN":"我也喪失很多記憶。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NULL","text":{"KOREA":"제 이름이 뭐였는지…… 우리 전대가 어떤 임무를 수행했는지…… 전부 다요.","JPN":"自分の名前は何だったのか……私たちの戦隊がどんな任務を遂行してきたのか……そのすべてを。","ENG":"What my name was... What missions our division performed... All of it.","TWN":"我叫什麼名字……小隊在執行什麼任務……我全都不記得。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NULL","text":{"KOREA":"……당신의 이름 조차도요. 아디트야 님.","JPN":"……あなたの名前さえもです。アーディティヤ様。","ENG":"...Even your name, Miss Aditya.","TWN":"……甚至是你的名字，阿迪亞。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};